func runPreCloseReviewGroup(ctx context.Context, reviewer BeadReviewer, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error) {
	if reviewer == nil {
		return nil, fmt.Errorf("review-group: reviewer required")
	}
	if groupReviewer, ok := reviewer.(reviewGroupReviewer); ok {
		return groupReviewer.ReviewGroup(ctx, beadID, resultRev, impl)
	}
	result, err := reviewer.ReviewBead(ctx, beadID, resultRev, impl)
	group := &ReviewGroupResult{
		BeadID:    beadID,
		ResultRev: resultRev,
		Slots: []ReviewGroupSlotResult{
			{
				ReviewerIndex: 0,
				Result:        result,
			},
		},
	}
	if err != nil {
		group.Slots[0].Error = err.Error()
	}
	return group, err
}

func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
	if group == nil || len(group.Slots) == 0 {
		return nil, fmt.Errorf("review-group: no review slots")
	}
	var firstApprove *ReviewResult
	var firstNonApprove *ReviewResult
	var firstResult *ReviewResult
	for _, slot := range group.Slots {
		if slot.Result != nil && firstResult == nil {
			firstResult = slot.Result
		}
		if slot.Error != "" && slot.Result == nil {
			if firstResult != nil {
				return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
			}
			return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
		}
		if slot.Result == nil {
			if firstResult != nil {
				return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
			}
			return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
		}
		res := slot.Result
		switch res.Verdict {
		case VerdictApprove:
			if !reviewResultHasACEvidence(res) {
				return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
			}
			if firstApprove == nil {
				firstApprove = res
			}
		case VerdictRequestChanges, VerdictBlock:
			if firstNonApprove == nil {
				firstNonApprove = res
			}
		default:
			if firstNonApprove == nil {
				firstNonApprove = res
			}
		}
	}
	if firstNonApprove != nil {
		return firstNonApprove, nil
	}
	return firstApprove, nil
}

func reviewResultHasACEvidence(res *ReviewResult) bool {
	if res == nil || res.Verdict != VerdictApprove {
		return false
	}
	if len(res.PerAC) == 0 {
		return false
	}
	for _, ac := range res.PerAC {
		if strings.TrimSpace(ac.Evidence) == "" {
			return false
		}
	}
	return true
}

// applyReviewTriageDecision runs the triage policy after a BLOCK or
// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
// prior review events to compute the BLOCK count, biases the result toward
// re-attempt when the latest BLOCK was paired with a degraded reviewer
// (kind:review-pairing-degraded), then applies the chosen action by writing
// metadata, labels, and a kind:triage-decision event.
//
// Errors from the underlying store are best-effort: callers continue
// regardless so a triage-side failure cannot strand a bead in an
// inconsistent review state. This callout previously lived as a method on
// ExecuteBeadWorker; the C3
// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
// driven by RunPostMergeReview / try.Attempt.
func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
	events, err := store.Events(beadID)
	if err != nil {
		return err
	}

	var blockTimestamps []time.Time
	var pairingDegraded []time.Time
	for _, ev := range events {
		switch {
		case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
			blockTimestamps = append(blockTimestamps, ev.CreatedAt)
		case ev.Kind == ReviewPairingDegradedEventKind:
			pairingDegraded = append(pairingDegraded, ev.CreatedAt)
		}
	}

	// History excludes the current attempt. The just-appended BLOCK (if any)
	// is the last entry in blockTimestamps and must not be counted as prior
	// history per triage.Decide()'s contract.
	historyCount := len(blockTimestamps)
	if historyCount > 0 {
		historyCount--
	}
	history := make([]triage.FailureMode, 0, historyCount)
	for i := 0; i < historyCount; i++ {
		history = append(history, triage.FailureModeReviewBlock)
	}

	policy := triage.DefaultPolicy()
	action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)

	pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
	if pairedDegraded && action == triage.ActionEscalateTier {
		action = triage.ActionReAttemptWithContext
	}

	return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
}

// latestBlockPairedDegraded reports whether the most recent BLOCK event was
// paired with a review-pairing-degraded event from the same attempt window
// (between the previous BLOCK and this one).
func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
	if len(blocks) == 0 || len(pairing) == 0 {
		return false
	}
	latest := blocks[len(blocks)-1]
	var prev time.Time
	if len(blocks) >= 2 {
		prev = blocks[len(blocks)-2]
	}
	for _, t := range pairing {
		if t.After(prev) && !t.After(latest) {
			return true
		}
	}
	return false
}

// applyTriageAction performs the side effects for a chosen Action: writes a
// tier-pin hint into bead.Extra (escalate_tier), appends a needs_human label
// (needs_human), and always records a kind:triage-decision event.
func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
	body := map[string]any{
		"action": string(action),
		"mode":   string(triage.FailureModeReviewBlock),
	}
	if pairedDegraded {
		body["pairing_degraded"] = true
	}

	switch action {
	case triage.ActionEscalateTier:
		nextTier := nextEscalatedTier(currentTier)
		body["tier_hint"] = string(nextTier)
		_ = store.Update(beadID, func(b *bead.Bead) {
			if b.Extra == nil {
				b.Extra = make(map[string]any)
			}
			b.Extra[TriageTierHintKey] = string(nextTier)
		})
	case triage.ActionNeedsHuman:
		_ = store.Update(beadID, func(b *bead.Bead) {
			if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
				b.Labels = append(b.Labels, TriageNeedsHumanLabel)
			}
		})
	}

	bodyJSON, _ := json.Marshal(body)
	return store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      triageDecisionEventKind,
		Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
		Body:      string(bodyJSON),
		Actor:     actor,
		Source:    "ddx agent execute-loop",
		CreatedAt: now,
	})
}

// nextEscalatedTier returns the next tier above `current`. An unrecognised or
// empty current tier defaults to standard; smart is its own ceiling.
func nextEscalatedTier(current string) escalation.ModelTier {
	switch escalation.ModelTier(current) {
	case escalation.TierCheap:
		return escalation.TierStandard
	case escalation.TierStandard:
		return escalation.TierSmart
	case escalation.TierSmart:
		return escalation.TierSmart
	default:
		return escalation.TierStandard
	}
}

		if maxInlinedFileBytes > 0 && len(body) > maxInlinedFileBytes {
			body = degradeDiffFileBody(f)
		}
		b2.WriteString(body)
	}
	return b2.String()
}

// degradeDiffFileBody returns a stat + hunk-headers only rendering of a diff
// file (FEAT-022 §1: large-file degradation). Used when a single file's body
// exceeds Caps.MaxInlinedFileBytes — preserves enough structure for the
// reviewer to know what changed without inlining the full content.
func degradeDiffFileBody(f evidence.DiffFile) string {
	var b strings.Builder
	b.WriteString("diff --git a/")
	b.WriteString(f.Path)
	b.WriteString(" b/")
	b.WriteString(f.Path)
	b.WriteString("\n")
	if f.Stat != "" {
		b.WriteString(f.Stat)
		b.WriteString("\n")
	}
	for _, h := range f.HunkHeaders {
		b.WriteString(h)
		b.WriteString("\n")
	}
	b.WriteString("[…file body omitted by ddx evidence cap…]\n")
	return b.String()
}

// mentionsPathLike returns true when text mentions the file path or its
// basename (a coarse heuristic — the reviewer only needs ranking, not
// exact symbolic resolution).
func mentionsPathLike(text, p string) bool {
	if text == "" || p == "" {
		return false
	}
	if strings.Contains(text, p) {
		return true
	}
	base := path.Base(p)
	return base != "" && base != "." && strings.Contains(text, base)
}

// pathsRelated returns true when refPath and filePath share a directory
// prefix or basename, used to associate diff files with governing
// documents.
func pathsRelated(refPath, filePath string) bool {
	if refPath == "" || filePath == "" {
		return false
	}
	refDir := path.Dir(refPath)
	if refDir != "" && refDir != "." && strings.HasPrefix(filePath, refDir+"/") {
		return true
	}
	if path.Base(refPath) == path.Base(filePath) {
		return true
	}
	return false
}

// reviewXMLEscape escapes &, <, and > for inclusion in XML text content.
func reviewXMLEscape(s string) string {
	var buf bytes.Buffer
	buf.WriteString(strings.NewReplacer(
		"&", "&amp;",
		"<", "&lt;",
		">", "&gt;",
	).Replace(s))
	return buf.String()
}

// DefaultBeadReviewer implements BeadReviewer by dispatching the review
// invocation through the agent service (or a test-injected runner).
// It fetches the bead, builds the review prompt, and runs the reviewer agent.
type DefaultBeadReviewer struct {
	ProjectRoot string
	BeadStore   BeadReader
	// Service, when non-nil, is the agentlib.FizeauService used to dispatch the
	// review invocation. Production callers leave this nil — ReviewBead
	// constructs a fresh service from ProjectRoot via NewServiceFromWorkDir.
	Service agentlib.FizeauService
	// Runner, when non-nil, replaces the service-based dispatch path. Used by
	// tests to return canned *Result values without spinning up a real
	// service. Takes precedence over Service.
	Runner AgentRunner
	// Harness and Model override the reviewer harness/model.
	// When Harness is empty, the reviewer follows the implementation harness;
	// when both are empty, dispatch is left to the agent service.
	Harness string
	Model   string
	// Caps configures the per-section evidence caps used when assembling
	// the review prompt (FEAT-022). When zero-valued, evidence.DefaultCaps
	// applies.
	Caps evidence.Caps
	// BeadEvents, when non-nil, is used to append the
	// kind:review-pairing-degraded event when the reviewer's resolved
	// provider matches the implementer's. Optional: nil disables the
	// telemetry emission while preserving the rest of the review flow.
	BeadEvents BeadEventAppender
}

// BuildReviewExecuteRequest constructs the AgentRunRuntime used for the
// post-merge reviewer dispatch. It pins the reviewer harness/model, attaches
// the implementer's correlation map (with role=reviewer overlaid), and
// derives MinPower as impl.ActualPower + 1 so routing is biased toward a
// stronger candidate than the implementer's actual selection. The returned
// runtime is missing per-call plumbing (Prompt/PromptFile, WorkDir,
// SessionLogDirOverride) — the caller fills those in before dispatching.
func BuildReviewExecuteRequest(impl ImplementerRouting, reviewerHarness, reviewerModel string) AgentRunRuntime {
	return BuildReviewGroupExecuteRequest(impl, reviewerHarness, reviewerModel, ReviewGroupDispatchMeta{})
}

// BuildReviewGroupExecuteRequest constructs the reviewer runtime for one
// slot in a review group. It threads the implementer's correlation facts,
// overlays reviewer role metadata, and stamps the review_group_id and
// reviewer_index when provided so downstream routing / tracing can join the
// two reviewer slots back to the same evidence bundle.
func BuildReviewGroupExecuteRequest(impl ImplementerRouting, reviewerHarness, reviewerModel string, meta ReviewGroupDispatchMeta) AgentRunRuntime {
	correlation := map[string]string{}
	for k, v := range impl.Correlation {
		correlation[k] = v
	}
	correlation["role"] = "reviewer"
	if meta.GroupID != "" {
		correlation["review_group_id"] = meta.GroupID
		correlation["reviewer_index"] = fmt.Sprintf("%d", meta.ReviewerIndex)
	}
	if impl.Harness != "" {
		correlation["impl_harness"] = impl.Harness
	}
	if impl.Provider != "" {
		correlation["impl_provider"] = impl.Provider
	}
	if impl.Model != "" {
		correlation["impl_model"] = impl.Model
	}
	if impl.ActualPower > 0 {
		correlation["impl_actual_power"] = fmt.Sprintf("%d", impl.ActualPower)
	}
	minPower := 0
	if impl.ActualPower > 0 {
		minPower = impl.ActualPower + 1
	}
	correlationID := reviewCorrelationID(correlation)
	return AgentRunRuntime{
		HarnessOverride:  reviewerHarness,
		ModelOverride:    reviewerModel,
		MinPowerOverride: minPower,
		Correlation:      correlation,
		Role:             "reviewer",
		CorrelationID:    correlationID,
	}
}

func reviewCorrelationID(correlation map[string]string) string {
	if len(correlation) == 0 {
		return ""
	}
	parts := make([]string, 0, 4)
	if beadID := correlation["bead_id"]; beadID != "" {
		parts = append(parts, beadID)
	}
	if groupID := correlation["review_group_id"]; groupID != "" {
		parts = append(parts, groupID)
	} else if resultRev := correlation["result_rev"]; resultRev != "" {
		parts = append(parts, resultRev)
	}
	if reviewerIndex := correlation["reviewer_index"]; reviewerIndex != "" {
		parts = append(parts, reviewerIndex)
	}
	if len(parts) == 0 {
		return ""
	}
	return strings.Join(parts, ":")
}

// reviewPairingDegradedBody renders the kind:review-pairing-degraded event
// body. The body carries both implementer and reviewer routing details so
// operators can see exactly which routes converged.
func reviewPairingDegradedBody(impl ImplementerRouting, reviewerHarness, reviewerProvider, reviewerModel string, reviewerPower int) string {
	var b strings.Builder
	fmt.Fprintf(&b, "impl_harness=%s\n", impl.Harness)
	fmt.Fprintf(&b, "impl_provider=%s\n", impl.Provider)
	fmt.Fprintf(&b, "impl_model=%s\n", impl.Model)
	fmt.Fprintf(&b, "impl_actual_power=%d\n", impl.ActualPower)
	fmt.Fprintf(&b, "reviewer_harness=%s\n", reviewerHarness)
	fmt.Fprintf(&b, "reviewer_provider=%s\n", reviewerProvider)
	fmt.Fprintf(&b, "reviewer_model=%s\n", reviewerModel)
	fmt.Fprintf(&b, "reviewer_actual_power=%d\n", reviewerPower)
	fmt.Fprintf(&b, "min_power_requested=%d\n", impl.ActualPower+1)
	return b.String()
}

// ReviewBead implements BeadReviewer.
func (r *DefaultBeadReviewer) ReviewBead(ctx context.Context, beadID, resultRev string, impl ImplementerRouting) (*ReviewResult, error) {
	b, err := r.BeadStore.Get(beadID)
	if err != nil {
		return nil, fmt.Errorf("reviewer: get bead %s: %w", beadID, err)
	}

	// Fetch the git diff for the commit being reviewed.
	diff, err := r.gitShow(resultRev)
	if err != nil {
		return nil, fmt.Errorf("reviewer: git show %s: %w", resultRev, err)
	}

	// Resolve governing document references.
	refs := ResolveGoverningRefs(r.ProjectRoot, b)

	// Determine iteration number from bead events.
	iter := 1

	// Build the review prompt under evidence caps.
	caps := r.Caps
	if caps.MaxPromptBytes == 0 {
		caps = evidence.DefaultCaps()
	}
	built := BuildReviewPromptBounded(b, iter, resultRev, diff, r.ProjectRoot, refs, BuildReviewPromptOptions{Caps: caps})
	prompt := built.Prompt
	attemptID := GenerateAttemptID()
	artifacts, err := createArtifactBundle(r.ProjectRoot, r.ProjectRoot, attemptID)
	if err != nil {
		return nil, fmt.Errorf("reviewer: create artifact bundle: %w", err)
	}
	if err := os.WriteFile(artifacts.PromptAbs, []byte(prompt), 0o644); err != nil {
		return nil, fmt.Errorf("reviewer: write prompt artifact: %w", err)
	}

	// Pre-dispatch short-circuit (FEAT-022 §7): if the assembled prompt
	// exceeds MaxPromptBytes after all per-section trimming, skip the
	// provider dispatch and return a typed review-error: context_overflow.
	// The bead is NOT closed — the loop's review-error event-append path
	// records the failure and leaves the bead open for retry.
	if built.Overflow {
		baseRev := resolveReviewBaseRev(r.ProjectRoot, resultRev)
		overflowTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			Harness:     r.Harness,
			Model:       r.Model,
		}
		reviewRes := &ReviewResult{
			Verdict:         VerdictBlock,
			Error:           evidence.OutcomeReviewContextOverflow,
			Rationale:       evidence.OutcomeReviewContextOverflow,
			ReviewerHarness: r.Harness,
			ReviewerModel:   r.Model,
			BaseRev:         baseRev,
			ResultRev:       resultRev,
			ExecutionDir:    artifacts.DirRel,
			CostUSD:         0,
			InputBytes:      overflowTelemetry.InputBytes,
			OutputBytes:     overflowTelemetry.OutputBytes,
		}
		_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
			Harness:          r.Harness,
			Model:            r.Model,
			BaseRev:          baseRev,
			ResultRev:        resultRev,
			Verdict:          string(VerdictBlock),
			BeadID:           beadID,
			ExecutionDir:     artifacts.DirRel,
			EvidenceAssembly: overflowTelemetry,
		}, reviewArtifactResult{
			Verdict:          string(VerdictBlock),
			Error:            evidence.OutcomeReviewContextOverflow,
			EvidenceAssembly: overflowTelemetry,
		})
		return reviewRes, fmt.Errorf("reviewer: PROMPT_BUDGET_EXCEEDED/context_overflow (assembled prompt %d bytes exceeds cap %d; see %s)",
			len(prompt), caps.MaxPromptBytes, artifacts.DirRel)
	}

	// Resolve reviewer harness and model. An explicit reviewer harness wins;
	// otherwise the reviewer follows the implementation harness. If both are
	// empty, leave routing unconstrained and let the agent service choose within
	// the MinPower bound.
	reviewHarness := r.Harness
	if reviewHarness == "" {
		reviewHarness = impl.Harness
	}
	reviewModel := r.Model
	if reviewModel == "" && reviewHarness != "" {
		reviewModel = ResolveModelTier(reviewHarness, SelectReviewerTier(escalation.TierSmart))
	}

	start := time.Now()
	runRuntime := BuildReviewExecuteRequest(impl, reviewHarness, reviewModel)
	runRuntime.Prompt = prompt
	runRuntime.WorkDir = r.ProjectRoot
	result, runErr := r.dispatchReviewRun(ctx, runRuntime)

	durationMS := int(time.Since(start).Milliseconds())
	if runErr != nil {
		// Transport-class failure (FEAT-022 §12): network or provider-side
		// error. Surface as a typed review-error so the loop classifies and
		// counts it correctly, rather than masquerading as a BLOCK verdict.
		transportTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			ElapsedMS:   durationMS,
			Harness:     reviewHarness,
			Model:       reviewModel,
		}
		reviewRes := &ReviewResult{
			Verdict:         VerdictBlock,
			Rationale:       runErr.Error(),
			Error:           evidence.OutcomeReviewTransport,
			ReviewerHarness: reviewHarness,
			ReviewerModel:   reviewModel,
			BaseRev:         resolveReviewBaseRev(r.ProjectRoot, resultRev),
			ResultRev:       resultRev,
			ExecutionDir:    artifacts.DirRel,
			DurationMS:      durationMS,
			CostUSD:         resultCost(result),
			InputBytes:      transportTelemetry.InputBytes,
			OutputBytes:     transportTelemetry.OutputBytes,
		}
		_ = writeReviewArtifacts(artifacts, reviewArtifactManifest{
			Harness:          reviewHarness,
			Model:            reviewModel,
			BaseRev:          reviewRes.BaseRev,
			ResultRev:        resultRev,
			Verdict:          string(reviewRes.Verdict),
			BeadID:           beadID,
			ExecutionDir:     artifacts.DirRel,
			EvidenceAssembly: transportTelemetry,
		}, reviewArtifactResult{
			Verdict:          string(reviewRes.Verdict),
			Rationale:        reviewRes.Rationale,
			Error:            reviewRes.Error,
			EvidenceAssembly: transportTelemetry,
		})
		return reviewRes, fmt.Errorf("reviewer: %s: %w", evidence.OutcomeReviewTransport, runErr)
	}

	actualHarness := reviewHarness
	actualModel := reviewModel
